import React, { useMemo, useRef, useEffect, useState } from "react";

const get = (obj, path, fallback = "") =>
  path.split(".").reduce((o, k) => (o && o[k] != null ? o[k] : null), obj) ?? fallback;

export default function Hourly({ hourly = [], activeTile = 0, onActiveTileChange }) {
  // Build a simple set of horizontally scrollable cards
  const list = useMemo(() => hourly.slice(0, 24), [hourly]);
  const scrollerRef = useRef(null);
  const [page, setPage] = useState(0);

  // snap-to-card pagination on mobile drag
  useEffect(() => {
    const el = scrollerRef.current;
    if (!el) return;
    const onScroll = () => {
      const w = el.clientWidth;
      const p = Math.round(el.scrollLeft / w);
      setPage(p);
    };
    el.addEventListener("scroll", onScroll, { passive: true });
    return () => el.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <div>
      <h2 className="text-lg font-semibold mb-2">Hourly</h2>
      <div
        ref={scrollerRef}
        className="flex overflow-x-auto snap-x snap-mandatory gap-3 pb-2 -mx-4 px-4"
      >
        {[0,1,2].map((tileIndex) => (
          <div
            key={tileIndex}
            className="min-w-full snap-start"
          >
            <div className="rounded-2xl p-4 border border-white/10 bg-white/10 dark:bg-white/5 backdrop-blur">
              <div className="flex justify-between items-center mb-3">
                <div className="text-sm opacity-80">Tile {tileIndex+1}</div>
                <button
                  className={`text-xs px-2 py-1 rounded-full border ${activeTile===tileIndex?"bg-white/40":"bg-white/10"}`}
                  onClick={() => onActiveTileChange && onActiveTileChange(tileIndex)}
                >Focus</button>
              </div>

              <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 gap-3">
                {list.map((h,i) => {
                  const dt = get(h, "dt", Math.floor(Date.now()/1000) + i*3600);
                  const label = new Date(dt*1000).toLocaleTimeString([], {hour: "numeric"});
                  const t = Math.round(get(h, "temp", 0));
                  const icon = get(h, "weather.0.icon", "01d");
                  return (
                    <div key={i} className="flex flex-col items-center text-sm">
                      <div className="opacity-70">{label}</div>
                      <img alt="" className="w-8 h-8" src={`https://openweathermap.org/img/wn/${icon}.png`} />
                      <div className="font-medium">{t}°</div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* mobile pagination dots */}
      <div className="mt-2 flex justify-center gap-2 sm:hidden">
        {[0,1,2].map((i) => (
          <span
            key={i}
            className={`inline-block w-2 h-2 rounded-full ${page===i?"bg-purple-500":"bg-white/30"}`}
          />
        ))}
      </div>
    </div>
  );
}
